INSERT INTO cms_content (site_code, column_id, title, content, source, author, content_type, status, publish_at, created_at, deleted) VALUES
('MAIN', 1, '遂宁市召开2024年度政府工作报告发布会', '1月15日上午，遂宁市2024年度政府工作报告发布会在市政府会议中心隆重举行。市长主持会议并作工作报告，全面回顾了过去一年的工作成果，部署了新一年重点工作任务。', '市政府办公室', '市政府办公室', 'news', '已发布', '2024-01-15 10:00:00', NOW(), 0),
('MAIN', 2, '遂宁市教育局发布2024年义务教育招生政策', '为进一步规范义务教育招生秩序，保障适龄儿童平等接受教育的权利，遂宁市教育局根据国家和省有关规定，结合我市实际，制定了2024年义务教育招生入学工作实施方案。', '市教育局', '市教育局', 'policy', '已发布', '2024-02-20 14:30:00', NOW(), 0),
('MAIN', 1, '遂宁市卫健委推进基层医疗卫生服务体系建设', '遂宁市卫健委深入贯彻落实健康中国战略，加快推进基层医疗卫生服务体系建设，提升基层医疗服务能力，让群众在家门口就能享受到优质便捷的医疗服务。', '市卫健委', '市卫健委', 'news', '已发布', '2024-03-05 09:15:00', NOW(), 0),
('MAIN', 1, '遂宁市政务服务一网通办成效显著', '遂宁市持续推进政务服务一网通办改革，优化办事流程，提升服务效能。截至目前，全市政务服务事项网上可办率达到95%以上，群众满意度持续提升。', '市政务服务中心', '市政务服务中心', 'news', '待审核', NULL, NOW(), 0),
('MAIN', 2, '遂宁市出台优化营商环境若干措施', '为持续优化营商环境，激发市场主体活力，遂宁市出台了一系列优化营商环境的政策措施，涵盖企业开办、项目审批、融资服务等多个方面。', '市发改委', '市发改委', 'policy', '已发布', '2024-03-18 16:00:00', NOW(), 0),
('MAIN', 1, '遂宁市开展2024年春风行动就业服务', '遂宁市人社局联合多部门开展2024年春风行动，为求职者和用人单位搭建对接平台，提供岗位信息、职业指导、政策咨询等全方位就业服务。', '市人社局', '市人社局', 'news', '已发布', '2024-02-28 11:00:00', NOW(), 0),
('MAIN', 1, '遂宁市生态环境局加强大气污染防治工作', '遂宁市生态环境局持续加强大气污染防治工作，严格落实各项管控措施，确保空气质量持续改善，守护好遂宁的蓝天白云。', '市生态环境局', '市生态环境局', 'news', '待审核', NULL, NOW(), 0),
('MAIN', 1, '遂宁市住建局推进老旧小区改造工程', '遂宁市住建局积极推进老旧小区改造工程，改善居民居住环境，提升城市品质。2024年计划改造老旧小区50个，惠及居民1.2万户。', '市住建局', '市住建局', 'news', '已发布', '2024-03-25 15:30:00', NOW(), 0);
